    unsigned BitWidth = Mask1->getBitWidth();
    ConstantRange MaskRange(APInt::getZero(BitWidth), 
                            Mask1->getZeroExtendValue() + 1);
    CR1 = CR1.intersectWith(MaskRange);
  }

  ConstantRange CR2 = ConstantRange::makeExactICmpRegion(
      IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
  if (Offset2)
    CR2 = CR2.subtract(*Offset2);
  if (Mask2) {
    unsigned BitWidth = Mask2->getBitWidth();
    ConstantRange MaskRange(APInt::getZero(BitWidth),
                            Mask2->getZeroExtendValue() + 1);
    CR2 = CR2.intersectWith(MaskRange);
  }

  Type *Ty = V1->getType();
  Value *NewV = V1;
  std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
  if (!CR) {
    if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
        CR2.isWrappedSet())
